     1→"use client";
     2→
     3→import useSWR from "swr";
     4→import Link from "next/link";
     5→import { semanticReleases as srApi, projects as projectsApi, releases as releasesApi, sources as sourcesApi } from "@/lib/api/client";
     6→import { useRouter } from "next/navigation";
     7→import { StatusDot } from "@/components/ui/status-dot";
     8→import { VersionChip } from "@/components/ui/version-chip";
     9→import { SectionLabel } from "@/components/ui/section-label";
    10→import { UrgencyCallout } from "@/components/ui/urgency-callout";
    11→import { ArrowLeft } from "lucide-react";
    12→import { ProviderBadge } from "@/components/ui/provider-badge";
    13→import { timeAgo } from "@/lib/format";
    14→
    15→export function SemanticReleaseDetail({ projectId, srId }: { projectId: string; srId: string }) {
    16→  const router = useRouter();
    17→  const { data, isLoading } = useSWR(`sr-${srId}`, () => srApi.get(srId));
    18→  const { data: projectData } = useSWR(`project-${projectId}`, () => projectsApi.get(projectId));
    19→  const { data: releasesData } = useSWR(`project-releases-${projectId}`, () => releasesApi.listByProject(projectId));
    20→  const { data: sourcesData } = useSWR(`project-sources-${projectId}`, () => sourcesApi.listByProject(projectId));
    21→
    22→  if (isLoading) {
    23→    return (
    24→      <div className="flex justify-center py-20">
    25→        <div className="text-[13px] text-[#9ca3af]" style={{ fontFamily: "var(--font-dm-sans)" }}>
    26→          Loading...
    27→        </div>
    28→      </div>
    29→    );
    30→  }
    31→
    32→  const sr = data?.data;
    33→  if (!sr) {
    34→    return (
    35→      <div className="flex justify-center py-20">
    36→        <div className="text-[13px] text-[#9ca3af]" style={{ fontFamily: "var(--font-dm-sans)" }}>
    37→          Semantic release not found
    38→        </div>
    39→      </div>
    40→    );
    41→  }
    42→
    43→  const project = projectData?.data;
    44→  const releasesList = releasesData?.data ?? [];
    45→  const sourcesList = sourcesData?.data ?? [];
    46→  const sourcesById = Object.fromEntries(sourcesList.map((s) => [s.id, s]));
    47→
    48→  const handleDelete = async () => {
    49→    if (!confirm("Delete this semantic release?")) return;
    50→    await srApi.delete(srId);
    51→    router.push("/semantic-releases");
    52→  };
    53→
    54→  return (
    55→    <div className="fade-in mx-auto max-w-[760px]">
    56→      {/* Back link */}
    57→      <Link
    58→        href="/semantic-releases"
    59→        className="mb-6 inline-flex items-center gap-1.5 transition-colors hover:opacity-70"
    60→        style={{
    61→          fontFamily: "var(--font-dm-sans)",
    62→          fontSize: "13px",
    63→          color: "#6b7280",
    64→        }}
    65→      >
    66→        <ArrowLeft size={14} />
    67→        Back to Semantic Releases
    68→      </Link>
    69→
    70→      {/* 2. Byline */}
    71→      {project?.name && (
    72→        <p
    73→          className="mb-1 text-[13px] italic text-[#9ca3af]"
    74→          style={{ fontFamily: "var(--font-fraunces)" }}
    75→        >
    76→          {project.name}
    77→        </p>
    78→      )}
    79→
    80→      {/* 3. Version heading */}
    81→      <h1
    82→        className="text-[42px] font-bold tracking-tight text-[#111113] leading-[1.1]"
    83→        style={{ fontFamily: "var(--font-fraunces)" }}
    84→      >
    85→        {sr.version}
    86→      </h1>
    87→
    88→      {/* 4. Meta line */}
    89→      <div
    90→        className="mt-3 flex items-center gap-2 text-[13px] text-[#6b7280]"
    91→        style={{ fontFamily: "var(--font-dm-sans)" }}
    92→      >
    93→        <StatusDot status={sr.status} />
    94→        <span className="flex-1">
    95→          {sr.status}
    96→          {sr.completed_at && ` \u00b7 generated ${timeAgo(sr.completed_at)}`}
    97→        </span>
    98→        <button
    99→          onClick={handleDelete}
   100→          className="rounded-md px-2.5 py-1 text-[12px] font-medium text-[#991b1b] transition-colors hover:bg-[#fef2f2]"
   101→          style={{ fontFamily: "var(--font-dm-sans)" }}
   102→        >
   103→          Delete
   104→        </button>
   105→      </div>
   106→
   107→      {/* 5. Divider */}
   108→      <hr className="my-8 border-0" style={{ borderTop: "1px solid #e8e8e5" }} />
   109→
   110→      {/* 6. Error state */}
   111→      {sr.error && (
   112→        <div
   113→          className="mb-8 rounded-md px-4 py-3 text-[14px] text-[#991b1b]"
   114→          style={{
   115→            border: "1px solid #fca5a5",
   116→            backgroundColor: "#fef2f2",
   117→            fontFamily: "var(--font-dm-sans)",
   118→          }}
   119→        >
   120→          {sr.error}
   121→        </div>
   122→      )}
   123→
   124→      {sr.report && (
   125→        <div className="space-y-10">
   126→          {/* 7. Summary section */}
   127→          <section>
   128→            <SectionLabel className="mb-3">Summary</SectionLabel>
   129→            <p
   130→              className="text-[16px] leading-[1.7] text-[#111113]"
   131→              style={{ fontFamily: "var(--font-dm-sans)" }}
   132→            >
   133→              {sr.report.summary}
   134→            </p>
   135→          </section>
   136→
   137→          {/* 8. Urgency callout */}
   138→          <UrgencyCallout urgency={sr.report.urgency} />
   139→
   140→          {/* 9. Availability + Adoption cards */}
   141→          <div className="grid grid-cols-2 gap-4">
   142→            <div
   143→              className="rounded-md p-5"
   144→              style={{ border: "1px solid #e8e8e5", backgroundColor: "#ffffff" }}
   145→            >
   146→              <SectionLabel className="mb-2">Availability</SectionLabel>
   147→              <p
   148→                className="text-[14px] leading-[1.6] text-[#111113]"
   149→                style={{ fontFamily: "var(--font-dm-sans)" }}
   150→              >
   151→                {sr.report.availability}
   152→              </p>
   153→            </div>
   154→            <div
   155→              className="rounded-md p-5"
   156→              style={{ border: "1px solid #e8e8e5", backgroundColor: "#ffffff" }}
   157→            >
   158→              <SectionLabel className="mb-2">Adoption</SectionLabel>
   159→              <p
   160→                className="text-[14px] leading-[1.6] text-[#111113]"
   161→                style={{ fontFamily: "var(--font-dm-sans)" }}
   162→              >
   163→                {sr.report.adoption}
   164→              </p>
   165→            </div>
   166→          </div>
   167→
   168→          {/* 10. Recommendation pull-quote */}
   169→          {sr.report.recommendation && (
   170→            <blockquote
   171→              className="rounded-md px-5 py-4 text-[18px] italic leading-[1.6] text-[#16181c]"
   172→              style={{
   173→                fontFamily: "var(--font-fraunces)",
   174→                borderLeft: "3px solid #e8601a",
   175→                backgroundColor: "#fafaf9",
   176→              }}
   177→            >
   178→              {sr.report.recommendation}
   179→            </blockquote>
   180→          )}
   181→        </div>
   182→      )}
   183→
   184→      {/* 11. Source Releases section */}
   185→      {releasesList.length > 0 && (
   186→        <section className="mt-10">
   187→          <SectionLabel className="mb-4">Source Releases</SectionLabel>
   188→          <div
   189→            className="overflow-hidden rounded-md"
   190→            style={{ border: "1px solid #e8e8e5" }}
   191→          >
   192→            <table className="w-full text-left">
   193→              <thead>
   194→                <tr style={{ backgroundColor: "#fafaf9", borderBottom: "1px solid #e8e8e5" }}>
   195→                  <th
   196→                    className="px-4 py-2.5 text-[11px] font-medium uppercase tracking-[0.08em] text-[#9ca3af]"
   197→                    style={{ fontFamily: "var(--font-dm-sans)" }}
   198→                  >
   199→                    Provider
   200→                  </th>
   201→                  <th
   202→                    className="px-4 py-2.5 text-[11px] font-medium uppercase tracking-[0.08em] text-[#9ca3af]"
   203→                    style={{ fontFamily: "var(--font-dm-sans)" }}
   204→                  >
   205→                    Repository
   206→                  </th>
   207→                  <th
   208→                    className="px-4 py-2.5 text-[11px] font-medium uppercase tracking-[0.08em] text-[#9ca3af]"
   209→                    style={{ fontFamily: "var(--font-dm-sans)" }}
   210→                  >
   211→                    Version
   212→                  </th>
   213→                  <th
   214→                    className="px-4 py-2.5 text-[11px] font-medium uppercase tracking-[0.08em] text-[#9ca3af]"
   215→                    style={{ fontFamily: "var(--font-dm-sans)" }}
   216→                  >
   217→                    Date
   218→                  </th>
   219→                </tr>
   220→              </thead>
   221→              <tbody>
   222→                {releasesList.map((rel) => {
   223→                  const source = sourcesById[rel.source_id];
   224→                  return (
   225→                    <tr
   226→                      key={rel.id}
   227→                      style={{ borderBottom: "1px solid #e8e8e5" }}
   228→                      className="last:border-b-0"
   229→                    >
   230→                      <td className="px-4 py-3">
   231→                        {source ? (
   232→                          <ProviderBadge provider={source.provider} />
   233→                        ) : (
   234→                          <span className="text-[12px] text-[#9ca3af]">{"\u2014"}</span>
   235→                        )}
   236→                      </td>
   237→                      <td className="px-4 py-3">
   238→                        <span
   239→                          className="text-[13px] text-[#374151]"
   240→                          style={{ fontFamily: "'JetBrains Mono', monospace" }}
   241→                        >
   242→                          {source?.repository ?? "\u2014"}
   243→                        </span>
   244→                      </td>
   245→                      <td className="px-4 py-3">
   246→                        <VersionChip version={rel.version} />
   247→                      </td>
   248→                      <td className="px-4 py-3">
   249→                        <span
   250→                          className="text-[13px] text-[#6b7280]"
   251→                          style={{ fontFamily: "var(--font-dm-sans)" }}
   252→                        >
   253→                          {timeAgo(rel.released_at ?? rel.created_at)}
   254→                        </span>
   255→                      </td>
   256→                    </tr>
   257→                  );
   258→                })}
   259→              </tbody>
   260→            </table>
   261→          </div>
   262→        </section>
   263→      )}
   264→    </div>
   265→  );
   266→}
