    24→  { href: "/subscriptions", label: "Subscriptions", icon: Bell },
    25→];
    26→
    27→export function Sidebar() {
    28→  const pathname = usePathname();
    29→  const [expanded, setExpanded] = useState(false);
    30→
    31→  return (
    32→    <aside
    33→      className={cn(
    34→        "flex shrink-0 flex-col transition-[width] duration-200",
    35→        expanded ? "w-[200px]" : "w-[52px]"
    36→      )}
    37→      style={{ backgroundColor: "#16181c" }}
    38→    >
    39→      {/* Logo + toggle */}
    40→      <div className="flex h-12 items-center px-3">
    41→        {expanded ? (
    42→          <>
    43→            <img src="/logo.svg" alt="" className="h-7 w-7 shrink-0" />
    44→            <Link
    45→              href="/"
    46→              className="ml-2 text-[16px] italic text-white"
    47→              style={{ fontFamily: "var(--font-fraunces)" }}
    48→            >
    49→              Changelogue
    50→            </Link>
    51→            <button
    52→              onClick={() => setExpanded(false)}
    53→              className="ml-auto text-[#9ca3af] transition-colors hover:text-white"
    54→              title="Collapse sidebar"
    55→            >
    56→              <PanelLeftClose className="h-4 w-4" />
    57→            </button>
    58→          </>
    59→        ) : (
    60→          <button
    61→            onClick={() => setExpanded(true)}
    62→            className="mx-auto text-[#9ca3af] transition-colors hover:text-white"
    63→            title="Expand sidebar"
    64→          >
    65→            <PanelLeftOpen className="h-4 w-4" />
    66→          </button>
    67→        )}
    68→      </div>
    69→
    70→      {/* Nav */}
    71→      <nav className="flex-1 pt-2">
    72→        {navItems.map((item) => {
    73→          const isActive =
    74→            item.href === "/"
    75→              ? pathname === "/"
    76→              : pathname.startsWith(item.href);
    77→          return (
    78→            <Link
    79→              key={item.href}
    80→              href={item.href}
    81→              title={expanded ? undefined : item.label}
    82→              className={cn(
    83→                "flex items-center gap-3 py-2 text-[13px] transition-colors duration-150",
    84→                expanded ? "pl-4 pr-3" : "justify-center px-0",
    85→                isActive
    86→                  ? "text-white"
    87→                  : "text-[#9ca3af] hover:text-white"
    88→              )}
    89→              style={
    90→                isActive
    91→                  ? {
    92→                      borderLeft: "3px solid #e8601a",
    93→                      backgroundColor: "rgba(255,255,255,0.06)",
    94→                      paddingLeft: expanded ? "13px" : undefined,
    95→                    }
    96→                  : { borderLeft: "3px solid transparent" }
    97→              }
    98→            >
    99→              <item.icon className="h-4 w-4 shrink-0" />
   100→              {expanded && (
   101→                <span style={{ fontFamily: "var(--font-dm-sans)" }}>
   102→                  {item.label}
   103→                </span>
   104→              )}
   105→            </Link>
   106→          );
   107→        })}
   108→      </nav>
   109→    </aside>
   110→  );
   111→}
