    25→
    26→function getRiskColors(riskLevel?: string) {
    27→  switch (riskLevel?.toUpperCase()) {
    28→    case "CRITICAL":
    29→      return { border: "#dc2626", bg: "#fff1f2", text: "#991b1b" };
    30→    case "HIGH":
    31→      return { border: "#d97706", bg: "#fff8f0", text: "#92400e" };
    32→    case "MEDIUM":
    33→      return { border: "#ca8a04", bg: "#fefce8", text: "#854d0e" };
    34→    case "LOW":
    35→    default:
    36→      return { border: "#16a34a", bg: "#f0fdf4", text: "#166534" };
    37→  }
    38→}
    39→
    40→function safeHostname(url: string): string {
    41→  try {
    42→    return new URL(url).hostname.replace("www.", "");
    43→  } catch {
    44→    return url;
    45→  }
    46→}
    47→
    48→export function SemanticReleaseDetail({
    49→  projectId,
    50→  srId,
    51→}: {
    52→  projectId: string;
    53→  srId: string;
    54→}) {
    55→  const router = useRouter();
    56→  const { data, isLoading } = useSWR(`sr-${srId}`, () => srApi.get(srId));
    57→  const { data: projectData } = useSWR(`project-${projectId}`, () =>
    58→    projectsApi.get(projectId),
    59→  );
    60→  const { data: srSourcesData } = useSWR(`sr-sources-${srId}`, () =>
    61→    srApi.getSources(srId),
    62→  );
    63→  const { data: sourcesData } = useSWR(`project-sources-${projectId}`, () =>
    64→    sourcesApi.listByProject(projectId),
    65→  );
    66→  const { data: contextSourcesData } = useSWR(
    67→    `project-context-sources-${projectId}`,
    68→    () => contextSources.list(projectId),
    69→  );
    70→
    71→  if (isLoading) {
    72→    return (
    73→      <div className="flex justify-center py-20">
    74→        <div
    75→          className="text-[13px] text-[#9ca3af]"
    76→          style={{ fontFamily: "var(--font-dm-sans)" }}
    77→        >
    78→          Loading...
    79→        </div>
    80→      </div>
    81→    );
    82→  }
    83→
    84→  const sr = data?.data;
    85→  if (!sr) {
    86→    return (
    87→      <div className="flex justify-center py-20">
    88→        <div
    89→          className="text-[13px] text-[#9ca3af]"
    90→          style={{ fontFamily: "var(--font-dm-sans)" }}
    91→        >
    92→          Semantic release not found
    93→        </div>
    94→      </div>
    95→    );
    96→  }
    97→
    98→  const project = projectData?.data;
    99→  const releasesList = srSourcesData?.data ?? [];
   100→  const sourcesList = sourcesData?.data ?? [];
   101→  const sourcesById = Object.fromEntries(sourcesList.map((s) => [s.id, s]));
   102→  const contextSourcesList = contextSourcesData?.data ?? [];
   103→
   104→  const handleDelete = async () => {
   105→    if (!confirm("Delete this semantic release?")) return;
   106→    try {
   107→      await srApi.delete(srId);
   108→      router.push("/semantic-releases");
   109→    } catch {
   110→      alert("Failed to delete semantic release.");
   111→    }
   112→  };
   113→
   114→  const report = sr.report;
   115→  const riskLevel = report?.risk_level?.toUpperCase();
   116→  const hasRiskOrUrgency = riskLevel || report?.urgency;
   117→  const riskColors = getRiskColors(riskLevel);
   118→
   119→  const statusChecks = report?.status_checks ?? [];
   120→  const downloadLinks = report?.download_links ?? [];
   121→  const downloadCommands = report?.download_commands ?? [];
   122→  const hasAvailabilitySection =
   123→    statusChecks.length > 0 ||
   124→    downloadLinks.length > 0 ||
   125→    downloadCommands.length > 0;
   126→
   127→  return (
   128→    <div className="fade-in mx-auto max-w-[760px]">
   129→      {/* 1. Back link */}
   130→      <Link
   131→        href="/semantic-releases"
   132→        className="mb-6 inline-flex items-center gap-1.5 transition-colors hover:opacity-70"
   133→        style={{
   134→          fontFamily: "var(--font-dm-sans)",
   135→          fontSize: "13px",
   136→          color: "#6b7280",
   137→        }}
   138→      >
   139→        <ArrowLeft size={14} />
   140→        Back to Semantic Releases
   141→      </Link>
   142→
   143→      {/* 2. Project byline */}
   144→      {project?.name && (
   145→        <p
   146→          className="mb-1 text-[13px] italic text-[#9ca3af]"
   147→          style={{ fontFamily: "var(--font-fraunces)" }}
   148→        >
   149→          {project.name}
   150→        </p>
   151→      )}
   152→
   153→      {/* 3. Version heading */}
   154→      <h1
   155→        className="text-[42px] font-bold tracking-tight text-[#111113] leading-[1.1]"
   156→        style={{ fontFamily: "var(--font-fraunces)" }}
   157→      >
   158→        {sr.version}
   159→      </h1>
   160→
   161→      {/* 4. Subject line */}
   162→      {report?.subject && (
   163→        <p
   164→          className="mt-2 text-[20px] leading-[1.4] text-[#374151]"
   165→          style={{ fontFamily: "var(--font-dm-sans)" }}
   166→        >
   167→          {report.subject}
   168→        </p>
   169→      )}
   170→
   171→      {/* 5. Meta line */}
   172→      <div
   173→        className="mt-3 flex items-center gap-2 text-[13px] text-[#6b7280]"
   174→        style={{ fontFamily: "var(--font-dm-sans)" }}
   175→      >
   176→        <StatusDot status={sr.status} />
   177→        <span className="flex-1">
   178→          {sr.status}
   179→          {sr.completed_at && ` \u00b7 generated ${timeAgo(sr.completed_at)}`}
   180→        </span>
   181→        <button
   182→          onClick={handleDelete}
   183→          className="rounded-md px-2.5 py-1 text-[12px] font-medium text-[#991b1b] transition-colors hover:bg-[#fef2f2]"
   184→          style={{ fontFamily: "var(--font-dm-sans)" }}
   185→        >
   186→          Delete
   187→        </button>
   188→      </div>
   189→
   190→      {/* 6. Divider */}
   191→      <hr
   192→        className="my-8 border-0"
   193→        style={{ borderTop: "1px solid #e8e8e5" }}
   194→      />
   195→
   196→      {/* 7. Error state */}
   197→      {sr.error && (
   198→        <div
   199→          className="mb-8 rounded-md px-4 py-3 text-[14px] text-[#991b1b]"
   200→          style={{
   201→            border: "1px solid #fca5a5",
   202→            backgroundColor: "#fef2f2",
   203→            fontFamily: "var(--font-dm-sans)",
   204→          }}
   205→        >
   206→          {sr.error}
   207→        </div>
   208→      )}
   209→
   210→      {report && (
   211→        <div className="space-y-10">
   212→          {/* 8. Risk & Urgency Banner */}
   213→          {hasRiskOrUrgency && (
   214→            <div
   215→              className="rounded-md px-4 py-4"
   216→              style={{
   217→                backgroundColor: riskColors.bg,
   218→                borderLeft: `3px solid ${riskColors.border}`,
   219→              }}
   220→            >
   221→              <div className="flex items-start gap-3">
   222→                <ShieldAlert
   223→                  className="h-5 w-5 mt-0.5 shrink-0"
   224→                  style={{ color: riskColors.border }}
   225→                />
   226→                <div className="flex-1">
   227→                  <div className="flex items-center gap-2 mb-1">
   228→                    {riskLevel && (
   229→                      <span
   230→                        className="rounded px-1.5 py-0.5 text-[11px] font-bold uppercase"
   231→                        style={{
   232→                          backgroundColor: riskColors.border,
   233→                          color: "#ffffff",
   234→                        }}
   235→                      >
   236→                        {riskLevel} RISK
   237→                      </span>
   238→                    )}
   239→                    {report.urgency && (
   240→                      <span
   241→                        className="text-[13px] font-medium"
   242→                        style={{ color: riskColors.text }}
   243→                      >
   244→                        {report.urgency} Urgency
   245→                      </span>
   246→                    )}
   247→                  </div>
   248→                  {report.risk_reason && (
   249→                    <p
   250→                      className="text-[14px] leading-[1.6]"
   251→                      style={{
   252→                        color: riskColors.text,
   253→                        fontFamily: "var(--font-dm-sans)",
   254→                      }}
   255→                    >
   256→                      {report.risk_reason}
   257→                    </p>
   258→                  )}
   259→                </div>
   260→              </div>
   261→            </div>
   262→          )}
   263→
   264→          {/* 9. Status Checks & Downloads */}
   265→          {hasAvailabilitySection && (
   266→            <section>
   267→              <SectionLabel className="mb-3">
   268→                Availability & Downloads
   269→              </SectionLabel>
   270→
   271→              {/* Status checks as green pills */}
   272→              {statusChecks.length > 0 && (
   273→                <div className="flex flex-wrap gap-2 mb-4">
   274→                  {statusChecks.map((check) => (
   275→                    <span
   276→                      key={check}
   277→                      className="inline-flex items-center gap-1.5 rounded-full px-3 py-1 text-[13px] font-medium"
   278→                      style={{
   279→                        backgroundColor: "#f0fdf4",
   280→                        color: "#166534",
   281→                        border: "1px solid #bbf7d0",
   282→                        fontFamily: "var(--font-dm-sans)",
   283→                      }}
   284→                    >
   285→                      <Check size={14} />
   286→                      {check}
   287→                    </span>
   288→                  ))}
   289→                </div>
   290→              )}
   291→
   292→              {/* Download links as pills */}
   293→              {downloadLinks.length > 0 && (
   294→                <div className="flex flex-wrap gap-2 mb-4">
   295→                  {downloadLinks.map((link) => (
   296→                    <a
   297→                      key={link}
   298→                      href={link}
