   300→                      rel="noopener noreferrer"
   301→                      className="inline-flex items-center gap-1.5 rounded-full px-3 py-1 text-[13px] font-medium transition-colors hover:opacity-80"
   302→                      style={{
   303→                        backgroundColor: "#f3f3f1",
