     1→package ingestion
     2→
     3→import (
     4→	"context"
     5→	"encoding/xml"
     6→	"fmt"
     7→	"net/http"
     8→	"strings"
     9→	"time"
    10→)
    11→
    12→const defaultGitHubURL = "https://github.com"
    13→
    14→// atomFeed represents a GitHub releases Atom feed.
    15→type atomFeed struct {
    16→	Entries []atomEntry `xml:"entry"`
    17→}
    18→
    19→type atomEntry struct {
    20→	ID      string `xml:"id"`
    21→	Updated string `xml:"updated"`
    22→	Content string `xml:"content"`
    23→	Link    struct {
    24→		Href string `xml:"href,attr"`
    25→	} `xml:"link"`
    26→}
    27→
    28→// GitHubAtomSource polls a GitHub repository's releases Atom feed.
    29→type GitHubAtomSource struct {
    30→	client     *http.Client
    31→	repository string
    32→	baseURL    string
    33→	sourceID   string
    34→}
    35→
    36→func NewGitHubAtomSource(client *http.Client, repository string, sourceID string) *GitHubAtomSource {
    37→	return &GitHubAtomSource{
    38→		client:     client,
    39→		repository: repository,
    40→		baseURL:    defaultGitHubURL,
    41→		sourceID:   sourceID,
    42→	}
    43→}
    44→
    45→func (s *GitHubAtomSource) Name() string     { return "github" }
    46→func (s *GitHubAtomSource) SourceID() string  { return s.sourceID }
    47→
    48→func (s *GitHubAtomSource) FetchNewReleases(ctx context.Context) ([]IngestionResult, error) {
    49→	feedURL := fmt.Sprintf("%s/%s/releases.atom", s.baseURL, s.repository)
    50→
    51→	req, err := http.NewRequestWithContext(ctx, http.MethodGet, feedURL, nil)
    52→	if err != nil {
    53→		return nil, fmt.Errorf("create request: %w", err)
    54→	}
    55→
    56→	resp, err := s.client.Do(req)
    57→	if err != nil {
    58→		return nil, fmt.Errorf("fetch atom feed: %w", err)
    59→	}
    60→	defer resp.Body.Close()
    61→
    62→	if resp.StatusCode != http.StatusOK {
    63→		return nil, fmt.Errorf("unexpected status: %d", resp.StatusCode)
    64→	}
    65→
    66→	var feed atomFeed
    67→	if err := xml.NewDecoder(resp.Body).Decode(&feed); err != nil {
    68→		return nil, fmt.Errorf("decode atom feed: %w", err)
    69→	}
    70→
    71→	results := make([]IngestionResult, 0, len(feed.Entries))
    72→	for _, entry := range feed.Entries {
    73→		version := extractVersion(entry.ID)
    74→		if version == "" {
    75→			continue
    76→		}
    77→		ts, _ := time.Parse(time.RFC3339, entry.Updated)
    78→		results = append(results, IngestionResult{
    79→			Repository: s.repository,
    80→			RawVersion: version,
    81→			Changelog:  entry.Content,
    82→			Metadata:   map[string]string{"release_url": entry.Link.Href},
    83→			Timestamp:  ts,
    84→		})
    85→	}
    86→	return results, nil
    87→}
    88→
    89→// extractVersion extracts the tag name from an Atom entry ID.
    90→// Format: "tag:github.com,2008:Repository/15452919/v1.17.0" -> "v1.17.0"
    91→func extractVersion(id string) string {
    92→	idx := strings.LastIndex(id, "/")
    93→	if idx < 0 || idx == len(id)-1 {
    94→		return ""
    95→	}
    96→	return id[idx+1:]
    97→}
    98→

