   163→// getReleaseDetail is the handler for the get_release_detail tool.
   164→func (f *toolFactory) getReleaseDetail(ctx tool.Context, input GetReleaseDetailInput) (GetReleaseDetailOutput, error) {
   165→	if input.ReleaseID == "" {
   166→		return GetReleaseDetailOutput{}, fmt.Errorf("release_id is required")
   167→	}
   168→
   169→	release, err := f.store.GetRelease(ctx, input.ReleaseID)
   170→	if err != nil {
   171→		return GetReleaseDetailOutput{}, fmt.Errorf("get release: %w", err)
   172→	}
   173→
   174→	out := GetReleaseDetailOutput{
   175→		ID:        release.ID,
   176→		SourceID:  release.SourceID,
   177→		Version:   release.Version,
   178→		RawData:   release.RawData,
   179→		CreatedAt: release.CreatedAt.Format("2006-01-02T15:04:05Z"),
   180→	}
   181→	if release.ReleasedAt != nil {
   182→		out.ReleasedAt = release.ReleasedAt.Format("2006-01-02T15:04:05Z")
   183→	}
   184→
   185→	return out, nil
   186→}
   187→
   188→// listContextSources is the handler for the list_context_sources tool.
   189→func (f *toolFactory) listContextSources(ctx tool.Context, input ListContextSourcesInput) (ListContextSourcesOutput, error) {
   190→	page := input.Page
   191→	if page < 1 {
   192→		page = 1
   193→	}
   194→	perPage := input.PerPage
   195→	if perPage < 1 || perPage > 50 {
   196→		perPage = 20
   197→	}
   198→
   199→	sources, total, err := f.store.ListContextSources(ctx, f.projectID, page, perPage)
   200→	if err != nil {
   201→		return ListContextSourcesOutput{}, fmt.Errorf("list context sources: %w", err)
   202→	}
   203→
   204→	items := make([]ContextSourceItem, 0, len(sources))
   205→	for _, s := range sources {
   206→		items = append(items, ContextSourceItem{
   207→			ID:     s.ID,
   208→			Type:   s.Type,
   209→			Name:   s.Name,
   210→			Config: s.Config,
   211→		})
   212→	}
   213→
   214→	return ListContextSourcesOutput{
   215→		Sources: items,
   216→		Total:   total,
   217→		Page:    page,
   218→		PerPage: perPage,
   219→	}, nil
   220→}
