     1→package routing
     2→
     3→import (
     4→	"bytes"
     5→	"context"
     6→	"encoding/json"
     7→	"fmt"
     8→	"net/http"
     9→	"strings"
    10→
    11→	"github.com/sentioxyz/changelogue/internal/models"
    12→)
    13→
    14→type slackConfig struct {
    15→	WebhookURL string `json:"webhook_url"`
    16→}
    17→
    18→// SlackSender sends notifications as Slack Block Kit messages via incoming webhook.
    19→type SlackSender struct {
    20→	Client *http.Client
    21→}
    22→
    23→// slackPayload is the Slack incoming webhook payload using Block Kit.
    24→type slackPayload struct {
    25→	Blocks []slackBlock `json:"blocks"`
    26→}
    27→
    28→type slackBlock struct {
    29→	Type     string      `json:"type"`
    30→	Text     *slackText  `json:"text,omitempty"`
    31→	Fields   []slackText `json:"fields,omitempty"`
    32→	Elements []slackText `json:"elements,omitempty"`
    33→}
    34→
    35→type slackText struct {
    36→	Type string `json:"type"`
    37→	Text string `json:"text"`
    38→}
    39→
    40→// riskEmoji returns an emoji indicator for the given risk level.
    41→func riskEmoji(level string) string {
    42→	switch strings.ToUpper(strings.TrimSpace(level)) {
    43→	case "LOW":
    44→		return "🟢"
    45→	case "MEDIUM":
    46→		return "🟡"
    47→	case "HIGH":
    48→		return "🔴"
    49→	case "CRITICAL":
    50→		return "⚫"
    51→	default:
    52→		return "⚪"
    53→	}
    54→}
    55→
    56→// buildSemanticBlocks builds rich Slack Block Kit blocks from a SemanticReport.
    57→func buildSemanticBlocks(title string, report *models.SemanticReport) []slackBlock {
    58→	blocks := []slackBlock{
    59→		{Type: "header", Text: &slackText{Type: "plain_text", Text: title}},
    60→	}
    61→
    62→	// Subject as the lead section
    63→	if report.Subject != "" {
    64→		blocks = append(blocks, slackBlock{
    65→			Type: "section",
    66→			Text: &slackText{Type: "mrkdwn", Text: fmt.Sprintf("*%s*", report.Subject)},
    67→		})
    68→	}
    69→
    70→	// Risk + Urgency + Availability as compact fields
    71→	blocks = append(blocks, slackBlock{
    72→		Type: "section",
    73→		Fields: []slackText{
    74→			{Type: "mrkdwn", Text: fmt.Sprintf("*Risk Level:*\n%s %s", riskEmoji(report.RiskLevel), report.RiskLevel)},
    75→			{Type: "mrkdwn", Text: fmt.Sprintf("*Urgency:*\n%s", report.Urgency)},
    76→			{Type: "mrkdwn", Text: fmt.Sprintf("*Availability:*\n%s", report.Availability)},
    77→		},
    78→	})
    79→
    80→	// Risk reason
    81→	if report.RiskReason != "" {
    82→		blocks = append(blocks,
    83→			slackBlock{Type: "divider"},
    84→			slackBlock{
    85→				Type: "section",
    86→				Text: &slackText{Type: "mrkdwn", Text: fmt.Sprintf("*Risk Assessment*\n%s", report.RiskReason)},
    87→			},
    88→		)
    89→	}
    90→
    91→	// Status checks
    92→	if len(report.StatusChecks) > 0 {
    93→		var items []string
    94→		for _, check := range report.StatusChecks {
    95→			items = append(items, fmt.Sprintf("• %s", check))
    96→		}
    97→		blocks = append(blocks,
    98→			slackBlock{Type: "divider"},
    99→			slackBlock{
   100→				Type: "section",
   101→				Text: &slackText{Type: "mrkdwn", Text: fmt.Sprintf("*Status Checks*\n%s", strings.Join(items, "\n"))},
   102→			},
   103→		)
   104→	}
   105→
   106→	// Changelog summary
   107→	summary := report.ChangelogSummary
   108→	if summary == "" {
   109→		summary = report.Summary
   110→	}
   111→	if summary != "" {
   112→		blocks = append(blocks,
   113→			slackBlock{Type: "divider"},
   114→			slackBlock{
   115→				Type: "section",
   116→				Text: &slackText{Type: "mrkdwn", Text: fmt.Sprintf("*Changelog*\n%s", summary)},
   117→			},
   118→		)
   119→	}
   120→
   121→	// Recommendation + Adoption
   122→	if report.Recommendation != "" {
   123→		blocks = append(blocks,
   124→			slackBlock{Type: "divider"},
   125→			slackBlock{
   126→				Type: "section",
   127→				Text: &slackText{Type: "mrkdwn", Text: fmt.Sprintf("*Recommendation*\n%s", report.Recommendation)},
   128→			},
   129→		)
   130→	}
   131→	if report.Adoption != "" {
   132→		blocks = append(blocks, slackBlock{
   133→			Type: "section",
   134→			Text: &slackText{Type: "mrkdwn", Text: fmt.Sprintf("*Adoption*\n%s", report.Adoption)},
   135→		})
   136→	}
   137→
   138→	// Download commands as code block
   139→	if len(report.DownloadCommands) > 0 {
   140→		blocks = append(blocks,
   141→			slackBlock{Type: "divider"},
   142→			slackBlock{
   143→				Type: "section",
   144→				Text: &slackText{Type: "mrkdwn", Text: fmt.Sprintf("*Download Commands*\n```%s```", strings.Join(report.DownloadCommands, "\n"))},
   145→			},
   146→		)
   147→	}
   148→
   149→	// Download links
   150→	if len(report.DownloadLinks) > 0 {
   151→		var links []string
   152→		for _, link := range report.DownloadLinks {
   153→			links = append(links, fmt.Sprintf("• <%s>", link))
   154→		}
   155→		blocks = append(blocks, slackBlock{
   156→			Type: "section",
   157→			Text: &slackText{Type: "mrkdwn", Text: fmt.Sprintf("*Download Links*\n%s", strings.Join(links, "\n"))},
   158→		})
   159→	}
   160→
   161→	// Footer context
   162→	blocks = append(blocks,
   163→		slackBlock{Type: "divider"},
   164→		slackBlock{
   165→			Type: "context",
   166→			Elements: []slackText{
   167→				{Type: "mrkdwn", Text: "📡 _Sent by Changelogue_"},
   168→			},
   169→		},
   170→	)
   171→
   172→	return blocks
   173→}
   174→
   175→func (s *SlackSender) Send(ctx context.Context, ch *models.NotificationChannel, msg Notification) error {
   176→	var cfg slackConfig
   177→	if err := json.Unmarshal(ch.Config, &cfg); err != nil {
   178→		return fmt.Errorf("parse slack config: %w", err)
   179→	}
   180→
   181→	// Try to parse body as a SemanticReport for rich formatting.
   182→	var blocks []slackBlock
   183→	var report models.SemanticReport
   184→	if err := json.Unmarshal([]byte(msg.Body), &report); err == nil && report.Subject != "" {
   185→		blocks = buildSemanticBlocks(msg.Title, &report)
   186→	} else {
   187→		// Fallback: simple header + body for non-report messages.
   188→		blocks = []slackBlock{
   189→			{Type: "header", Text: &slackText{Type: "plain_text", Text: msg.Title}},
   190→			{Type: "section", Text: &slackText{Type: "mrkdwn", Text: msg.Body}},
   191→		}
   192→	}
   193→
   194→	payload := slackPayload{Blocks: blocks}
   195→
   196→	body, err := json.Marshal(payload)
   197→	if err != nil {
   198→		return fmt.Errorf("marshal slack payload: %w", err)
   199→	}
   200→
   201→	req, err := http.NewRequestWithContext(ctx, http.MethodPost, cfg.WebhookURL, bytes.NewReader(body))
   202→	if err != nil {
   203→		return fmt.Errorf("create request: %w", err)
   204→	}
   205→	req.Header.Set("Content-Type", "application/json")
   206→
   207→	client := s.Client
   208→	if client == nil {
   209→		client = http.DefaultClient
   210→	}
   211→
   212→	resp, err := client.Do(req)
   213→	if err != nil {
   214→		return fmt.Errorf("send slack notification: %w", err)
   215→	}
   216→	defer resp.Body.Close()
   217→
   218→	if resp.StatusCode >= 400 {
   219→		return fmt.Errorf("slack returned status %d", resp.StatusCode)
   220→	}
   221→	return nil
   222→}
